INSERT INTO question (category_id, question_type, title, options_json, correct_answer, explanation, difficulty, source_number, status, create_time, update_time) VALUES (NULL, 'MULTI', '结肠镜检查术的肠道准备要求', '[{"label": "A", "text": "检查前2~3天开始进少渣、低脂软食"}, {"label": "B", "text": "检查前1天进流质饮食 当天晨禁食"}, {"label": "C", "text": "检查前天晚口服番泻叶或其他泻药 同时饮水1000mL"}, {"label": "D", "text": "检查前1小时用温水做清洁灌肠 也可采用20%甘露醇500mL和5%葡萄糖氯化钠注射1000mL混合液于检查前1天傍晚口服"}, {"label": "E", "text": "术前遵医嘱肌内注射地西泮5~10mg 哌替啶50mg 阿托品0.5mg-以镇静抑制肠蠕动"}]', 'ABCDE', NULL, 2, 457, 1, NOW(), NOW());
