INSERT INTO question (category_id, question_type, title, options_json, correct_answer, explanation, difficulty, source_number, status, create_time, update_time) VALUES (NULL, 'MULTI', '病人，女，34岁，风湿性心脏病史16年，因感冒、发热住院。医嘱静脉输液，上午8点开始输液，每分钟滴速40滴，但病人自己嫌滴得太慢，自行调节滴速达100滴/min，半小时后病人出现呼吸急促，剧烈咳嗽，痰液呈泡沫血性，不能平卧。护士应采取的正确护理措施是', '[{"label": "A", "text": "立即停止输液"}, {"label": "B", "text": "病人端坐，双腿下垂"}, {"label": "C", "text": "必要时进行四肢轮扎"}, {"label": "D", "text": "给予高流量氧气吸入"}, {"label": "E", "text": "遵医嘱给予强心、利尿、扩血管的药物"}]', 'ABCDE', NULL, 2, 609, 1, NOW(), NOW());
