INSERT INTO question (category_id, question_type, title, options_json, correct_answer, explanation, difficulty, source_number, status, create_time, update_time) VALUES (NULL, 'SINGLE', '以上月经期子宫内膜的变化,属于分泌期的是', '[{"label": "A", "text": "月经周期的第5~第14天，子宫内膜只留下基底层，在雌激素的影响下，内膜逐渐生长变厚"}, {"label": "B", "text": "月经周期的第5~第1天，子宫内膜继续增厚，腺体增大，卵巢黄体形成"}, {"label": "C", "text": "月经周期的第1~第4天，雌激素水平降低，内膜螺旋小动脉开始节段性和阵发性收缩、痉挛"}, {"label": "D", "text": "月经周期的第15~第24天，子宫内膜继续增厚，腺体增大，卵巢黄体形成"}, {"label": "E", "text": "月经周期的第15~第2"}]', 'D', NULL, 2, 786, 1, NOW(), NOW());
