INSERT INTO question (category_id, question_type, title, options_json, correct_answer, explanation, difficulty, source_number, status, create_time, update_time) VALUES (NULL, 'SINGLE', '水针操作时,下述错误的是', '[{"label": "A", "text": "严格无菌操作;防止感染"}, {"label": "B", "text": "治疗时应对患者说明治疗特点和注射后的正常反应。如注射后局部可能有酸胀感48小时内局部有轻度不适有时持续时间较长但一般不超过1天"}, {"label": "C", "text": "副作用大或刺激性强的药物宜做深部注射"}, {"label": "D", "text": "药液不可注入血管、关节腔、脊髓腔、胸腔内以免造成不良后果"}, {"label": "E", "text": "孕妇的下腹部、腰骶部和合谷、三阴交等禁用以免流产。年老体弱者选穴宜少药液剂量酌减"}]', 'C', NULL, 2, 790, 1, NOW(), NOW());
