INSERT INTO question (category_id, question_type, title, options_json, correct_answer, explanation, difficulty, source_number, status, create_time, update_time) VALUES (NULL, 'SINGLE', '下列压力蒸汽灭菌器化学鉴别不符合要求的是', '[{"label": "A", "text": "化学指示胶带监测法是将化学指示胶带粘贴于物品包外，经过一个灭菌周期后，观察其颜色的变化"}, {"label": "B", "text": "化学指示管(卡)监测法是将化学指示管(卡)放入大包和难以消毒部位的物品包中央，经过一个灭菌周期后，取出指示管(卡)，根据其颜色及形状的改变判断是否达到灭菌条件"}, {"label": "C", "text": "指示图又称B-D试验要求每周第一次空锅测试，用时放置标准敷料包(30cm×30cm×25cm)内的中央层，并将包放于柜室贴近排气口上方，每周1次灭菌处理后，观察指示图变色情况判断是否达到灭菌标准"}, {"label": "D", "text": "判断所用化学指示物需经过卫生部批准，并在有效期内使用"}, {"label": "E", "text": "指示图又称B-D试验要求每天第一次空锅测试，用时放置标准敷料包(30cm×30cm×25cm)内的中央层，并将包放于柜室贴近排气口上方，每天1次，灭菌处理后，观察指示图变色情况判断是否达到灭菌标准"}]', 'C', NULL, 2, 941, 1, NOW(), NOW());
